import React, { createContext, useState, useContext } from 'react';
import api from './api';
import { useAuth } from './AuthContext';
import { useDevMode } from './DevModeContext';
import { useDevApi } from '../utils/devApi';

const ChatContext = createContext();

export const useChat = () => {
  const context = useContext(ChatContext);
  if (!context) {
    throw new Error('useChat must be used within a ChatProvider');
  }
  return context;
};

export const ChatProvider = ({ children }) => {
  const [sessions, setSessions] = useState([]);
  const [currentSession, setCurrentSession] = useState(null);
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(false);
  const [showLoginPrompt, setShowLoginPrompt] = useState(false);
  const { authBypassed } = useDevMode();
  const devApi = useDevApi();

  const fetchSessions = async () => {
    try {
      const sessions = await api.getChatSessions();
      setSessions(sessions);
    } catch (error) {
      console.error('Failed to fetch sessions:', error);
    }
  };

  const createSession = async (title) => {
    try {
      const newSession = await api.createChatSession(title);
      setSessions([newSession, ...sessions]);
      setCurrentSession(newSession);
      setMessages([]);
      return newSession;
    } catch (error) {
      console.error('Failed to create session:', error);
      return null;
    }
  };

  const fetchSession = async (sessionId) => {
    try {
      const response = await axios.get(`/chat/sessions/${sessionId}`);
      const session = response.data;
      setCurrentSession(session);
      setMessages(session.messages || []);
      return session;
    } catch (error) {
      console.error('Failed to fetch session:', error);
      return null;
    }
  };

  const sendMessage = async (message, sessionId = null) => {
    if (!sessionId && !currentSession) {
      // Create new session with first message
      const newSession = await createSession(message.substring(0, 50));
      if (!newSession) return null;
      sessionId = newSession.id;
    } else if (!sessionId) {
      sessionId = currentSession.id;
    }

    setLoading(true);

    // Add user message immediately for better UX
    const userMessage = {
      id: Date.now(),
      content: message,
      message_type: 'user',
      created_at: new Date().toISOString(),
    };

    setMessages(prev => [...prev, userMessage]);

    try {
      let response;

      // Use dev API if auth is bypassed, otherwise use normal API
      if (authBypassed) {
        console.log('🔓 Using dev API (auth bypassed)');
        response = await devApi.sendMessage(
          messages.map(msg => ({
            role: msg.message_type === 'user' ? 'user' : 'assistant',
            content: msg.content,
            timestamp: msg.created_at
          })),
          message,
          null, // context
          sessionId
        );
      } else {
        console.log('🔒 Using normal API (auth required)');
        response = await axios.post('/chat', {
          message,
          session_id: sessionId,
        });
      }

      // Handle different response formats
      let aiResponse, intent_type, structured_content;

      if (response.provider_used) {
        // Dev API response
        aiResponse = response.content;
        intent_type = response.content_type;
        structured_content = response.structured_data;
      } else {
        // Normal API response
        const responseData = response.data;
        aiResponse = responseData.response;
        intent_type = responseData.intent_type;
        structured_content = responseData.structured_content;
      }

      // Add AI response
      const assistantMessage = {
        id: Date.now() + 1,
        content: aiResponse,
        message_type: 'assistant',
        created_at: new Date().toISOString(),
        intent_type,
        structured_content,
      };

      setMessages(prev => [...prev, assistantMessage]);

      // Update session in list (only for normal API)
      if (!authBypassed && currentSession && currentSession.id === sessionId) {
        setCurrentSession(prev => ({
          ...prev,
          updated_at: new Date().toISOString(),
          messages: [...prev.messages, userMessage, assistantMessage],
        }));
      }

      return response;
    } catch (error) {
      console.error('Failed to send message:', error);

      // Remove user message if request failed
      setMessages(prev => prev.filter(msg => msg.id !== userMessage.id));

      return null;
    } finally {
      setLoading(false);
    }
  };

  const deleteSession = async (sessionId) => {
    try {
      await axios.delete(`/chat/sessions/${sessionId}`);
      setSessions(prev => prev.filter(session => session.id !== sessionId));

      if (currentSession?.id === sessionId) {
        setCurrentSession(null);
        setMessages([]);
      }
    } catch (error) {
      console.error('Failed to delete session:', error);
    }
  };

  const value = {
    sessions,
    currentSession,
    messages,
    loading,
    showLoginPrompt,
    setShowLoginPrompt,
    fetchSessions,
    createSession,
    fetchSession,
    sendMessage,
    deleteSession,
    setCurrentSession,
  };

  return (
    <ChatContext.Provider value={value}>
      {children}
    </ChatContext.Provider>
  );
};
